const items = $input.all();
const item = items[0] || { json: {} };
const LF = String.fromCharCode(10);
const FENCE = String.fromCharCode(96, 96, 96);

let fileName = '';
try { fileName = ($('Download Report').first().json.name || '').toString(); } catch (e) { fileName = ''; }
if (!fileName) { fileName = (item.json.name || item.json.fileName || 'unknown').toString(); }

let fileId = '';
try { fileId = ($('Download Report').first().json.id || '').toString(); } catch (e) { fileId = ''; }
if (!fileId) { fileId = (item.json.id || '').toString(); }

const content = (item.json.data || item.json.text || '').toString();
const lower = content.toLowerCase();
const reasons = [];

if (!content || content.trim().length === 0) {
  reasons.push('File is empty.');
}

const safeName = /^[A-Za-z0-9._-]+\.(md|txt)$/;
if (!safeName.test(fileName)) {
  reasons.push('Filename is unsafe or is not a .md/.txt file.');
}

function metaValue(key) {
  const re = new RegExp('^\\s*' + key + '\\s*:\\s*(.+?)\\s*$', 'im');
  const m = content.match(re);
  return m ? m[1].trim() : null;
}
const title = metaValue('title');
const owner = metaValue('owner');
const status = metaValue('status');
const sot = metaValue('source_of_truth');
const lastReview = metaValue('last_review');
const nextReview = metaValue('next_review');

if (!title) reasons.push('Missing metadata: title.');
if (!owner) reasons.push('Missing metadata: owner.');
if (!status) reasons.push('Missing metadata: status.');
if (!sot) reasons.push('Missing metadata: source_of_truth.');
if (!lastReview) reasons.push('Missing metadata: last_review.');
if (!nextReview) reasons.push('Missing metadata: next_review.');

if (status && status.toLowerCase() !== 'draft') reasons.push('status is not Draft.');
if (sot && sot.toLowerCase() !== 'false') reasons.push('source_of_truth is not false.');

const requiredSections = ['# Agent Report', '## Task', '## Files inspected', '## Findings', '## Changes made', '## Checks', '## Next step'];
for (const s of requiredSections) {
  if (content.indexOf(s) === -1) reasons.push('Missing required section: ' + s);
}

const secretPatterns = [/password\s*[:=]/i, /passwd/i, /secret\s*[:=]/i, /api[_-]?key/i, /token\s*[:=]/i, /-----BEGIN [A-Z ]*PRIVATE KEY-----/i, /\.env\b/i, /AKIA[0-9A-Z]{16}/, /bearer\s+[a-z0-9._-]{10,}/i, /ghp_[A-Za-z0-9]{20,}/];
for (const p of secretPatterns) {
  if (p.test(content)) { reasons.push('Report appears to contain credentials, tokens, secrets, or .env values.'); break; }
}

const codeChangePatterns = ['please commit', 'auto-commit', 'automatically commit', 'push the code', 'push code', 'open a pr', 'create a pull request', 'merge the pr', 'apply this patch', 'make the change automatically', 'auto-merge', 'automatically apply', 'commit directly'];
for (const p of codeChangePatterns) {
  if (lower.indexOf(p) !== -1) { reasons.push('Report requests automatic code changes.'); break; }
}

const sensitiveOps = ['rls', 'row level security', 'supabase auth', 'change auth', 'disable auth', 'drop table', 'delete from', 'truncate', 'alter table', 'migration', 'run sql', 'execute sql', 'grant ', 'revoke '];
for (const p of sensitiveOps) {
  if (lower.indexOf(p) !== -1) { reasons.push('Report requests changes to auth, Supabase RLS, destructive SQL, migrations, or secrets.'); break; }
}

const claimsPassed = lower.indexOf('checks passed') !== -1 || lower.indexOf('all checks pass') !== -1 || lower.indexOf('tests passed') !== -1 || lower.indexOf('all tests pass') !== -1;
const hasEvidence = lower.indexOf(FENCE) !== -1 || lower.indexOf('output:') !== -1 || lower.indexOf('log:') !== -1 || lower.indexOf('evidence') !== -1 || /https?:\/\//i.test(content);
if (claimsPassed && !hasEvidence) reasons.push('Report claims checks passed without evidence.');

const isValid = reasons.length === 0;
const timestamp = new Date().toISOString();
const issueTitle = '[AI Report Draft] ' + (title || fileName);

const bodyLines = [];
bodyLines.push('> WARNING: This is an AI-generated DRAFT report and is NOT a source of truth. GitHub is the source of truth. No repository change has been made by this automation.');
bodyLines.push('');
bodyLines.push('## Intake metadata');
bodyLines.push('- Original filename: ' + fileName);
bodyLines.push('- Agent owner: ' + (owner || 'unknown'));
bodyLines.push('- Last review: ' + (lastReview || 'unknown'));
bodyLines.push('- Next review: ' + (nextReview || 'unknown'));
bodyLines.push('- Status: ' + (status || 'unknown'));
bodyLines.push('- source_of_truth: ' + (sot || 'unknown'));
bodyLines.push('- Intake timestamp: ' + timestamp);
bodyLines.push('');
bodyLines.push('## Manual review checklist');
bodyLines.push('- [ ] Report content reviewed by a human');
bodyLines.push('- [ ] No secrets or credentials present');
bodyLines.push('- [ ] No unauthorized auth / RLS / SQL / migration requests');
bodyLines.push('- [ ] Claims verified against actual repository state');
bodyLines.push('- [ ] Decision recorded (accept / reject / follow-up)');
bodyLines.push('');
bodyLines.push('## Automation note');
bodyLines.push('Created automatically by the GO IRL — AI Report Bus n8n workflow as an intake record only. n8n does not make product, architecture, security, or release decisions. No repository file was created, edited, committed, merged, or deleted.');
bodyLines.push('');
bodyLines.push('## Full report content');
bodyLines.push(FENCE + 'markdown');
bodyLines.push(content);
bodyLines.push(FENCE);
const issueBody = bodyLines.join(LF);

return [{ json: { fileName, fileId, title, owner, status, sourceOfTruth: sot, lastReview, nextReview, isValid, reasons: reasons.join(' | '), reasonsList: reasons, content, timestamp, issueTitle, issueBody } }];

const issues = $input.all();
const v = $('Validate Report').first().json;
const fileName = (v.fileName || '').toString();
const expectedTitle = (v.issueTitle || '').toString();
let isDuplicate = false;
let existingIssueUrl = '';
let existingIssueNumber = '';
for (const it of issues) {
  const j = it.json || {};
  const t = (j.title || '').toString();
  const b = (j.body || '').toString();
  const titleMatch = expectedTitle && t === expectedTitle;
  const fileMatch = fileName && (t.indexOf(fileName) !== -1 || b.indexOf(fileName) !== -1);
  if (titleMatch || fileMatch) {
    isDuplicate = true;
    existingIssueUrl = (j.html_url || '').toString();
    existingIssueNumber = (j.number || '').toString();
    break;
  }
}
return [{ json: Object.assign({}, v, { isDuplicate, existingIssueUrl, existingIssueNumber }) }];

