const v = $('Validate Report').first().json;
const LF = String.fromCharCode(10);
const lines = [];
lines.push('GO IRL AI Report - Rejection Log');
lines.push('Filename: ' + (v.fileName || 'unknown'));
lines.push('Result: REJECTED');
lines.push('Timestamp: ' + new Date().toISOString());
lines.push('Reasons:');
const rl = v.reasonsList || [];
for (const r of rl) { lines.push('- ' + r); }
return [{ json: { fileName: v.fileName, result: 'REJECTED', reasons: v.reasons, reasonsList: rl, logText: lines.join(LF), timestamp: new Date().toISOString() } }];

